var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"제이크?","JPN":"ジェイク？","ENG":"Jake?","TWN":"傑克？"},"stage":{"bg":"sky","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"오랜만에 왔어요. 어머니.","JPN":"久しぶりに戻ったよ、母さん。","ENG":"Long time no see, Mom.","TWN":"我有好久沒回來了吧，母親。"},"stage":{"bg":"sky","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"오지 않을 줄 알았단다.","JPN":"もう来ないのかと思ったわ。","ENG":"I thought you'd never come.","TWN":"我以為你不會來了。"},"stage":{"bg":"sky","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"네 아버진......","JPN":"あなたのお父さんは……","ENG":"Your father...","TWN":"你父親……"},"stage":{"bg":"sky","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"늦어서 죄송해요.","JPN":"遅くなってごめん。","ENG":"Sorry I'm late.","TWN":"對不起，我遲到了。"},"stage":{"bg":"sky","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"혹시, 아버지의 물건은 정리된 건가요?","JPN":"もしかして、父さんの遺品を整理した？","ENG":"Did you sort out all his belongings by the way?","TWN":"父親的東西都整理好了嗎？"},"stage":{"bg":"sky","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"으응, 아직은 치우지 않았다.","JPN":"ううん、まだ整理してないの。","ENG":"Yes, but I haven't put them away yet.","TWN":"嗯，我還沒有收拾掉。"},"stage":{"bg":"sky","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"서재 방에 모아뒀으니 한 번 확인해보렴.","JPN":"書斎に集めておいたから、一度確認してみなさい。","ENG":"They're all in his study, if you'd like to take a look.","TWN":"我放在書房裡了，你去確認一下吧。"},"stage":{"bg":"sky","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"네, 고마워요.","JPN":"うん、ありがとう。","ENG":"I will. Thank you.","TWN":"好的，謝謝。"},"stage":{"bg":"sky","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이 작은 상자에 들어있는 게 전부인가?","JPN":"この小さな箱に入ってるのが全部なのか？","ENG":"It's such a small box... Is this everything?","TWN":"這小箱子裡的就是全部了嗎？"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"......일평생 돈을 그렇게 열심히 벌었는데, 뭐 하나 남질 않았군요.","JPN":"……一生懸命働いて稼いだくせに、何一つ残ってないな。","ENG":"You worked so hard all your life, yet you left so little behind.","TWN":"……努力賺了一輩子錢，結果剩下的只有這些啊。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"음? 이 수첩은...... 아버지가 쓰던 일지인가.","JPN":"うん？　この手帳は……父さんが書いていた日誌か。","ENG":"Huh? This notepad... Is this his journal?","TWN":"嗯？這個筆記本……看來是父親的筆記啊。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"지난 번에 있었던 남부의 대규모 침식사태 이후, 국가가 예산을 풀어 적극적으로 용병들을 불러모으기 시작했다. 한동안 꽤 바빠질 예정이다.","JPN":"先日起きた南部での大規模侵食事態以後、国が予算を投入して積極的に傭兵たちを呼び集めはじめた。\\nしばらくはとても忙しくなりそうだ。","ENG":"After the widespread Corruption in the south last time, the government decided to allocate funding to aggressively mobilize mercenaries. Looks like I'll be busy for a while now.","TWN":"自從上次南部遭受了大規模侵蝕，國家開始投入預算積極召集傭兵。看來會忙上一段時間了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"스무 명 정도의 아이들을 난민지구로 호송하는 동안, 또 다시 중규모의 침식사태가 일어났다.","JPN":"20人あまりの子供たちを難民地区に護送する間、再び中規模侵食事態が発生した。","ENG":"While we escorted around two dozen children to the refugee district, another mid-scale Corruption Disaster took place.","TWN":"護送20名左右的孩子到難民區域，期間又發生了中規模侵蝕。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"도시외곽의 난민들은 언제나 위험에 노출되어있고, 방위군은 ‘균열’을 막아내느라 내부에 신경 쓸 전력이 부족하다.","JPN":"都市近郊にいる難民たちは常に危険にさらされていて、\\n防衛軍は「亀裂」を防ぐことに精一杯だから内部を取りまとめる戦力が足りない。","ENG":"The refugees in the city outskirts are always vulnerable, while the defending forces are too preoccupied with keeping the \\"Rift\\" sealed to attend to the city.","TWN":"城市週邊的難民隨時暴露在危險之中，防衛軍則要阻止''裂變''，根本沒有多餘戰力。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"최근 들어 난기류가 잦다. 대낮에 하늘이 붉게 물들기도 한다. 침식지역 일대는 이런 이변현상이 심하다던데.","JPN":"最近になって乱気流が頻繁に発生している。昼間に空が赤く染まる日もあった。\\n侵食地域一帯ではこのような異変現象がひどいらしい。","ENG":"Turbulence comes often recently. The sky turns red in mid-day sometimes. I heard such disturbances are severe in the disaster zones.","TWN":"最近發生很多亂流。在日光下天空被染成了紅色，聽說侵蝕區域內這種異常現象更加嚴重。"},"stage":{"bg":"WARZONE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 육로를 통하는 것은 훨씬 위험하기 때문에 선택의 여지가 없다.","JPN":"しかし、陸路で渡ることはもっと危険だから他に選択肢はない。","ENG":"But we have no choice but to fly, as ground movement is even more dangerous.","TWN":"但是現在走陸路更危險，我別無選擇。"},"stage":{"bg":"WARZONE_03","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};